// ksef-auth zwraca:
// msg.payload = { accessToken, accessTokenValidUntil, refreshToken, refreshTokenValidUntil }
flow.set("accessToken", msg.payload.accessToken);
flow.set("accessTokenValidUntil", msg.payload.accessTokenValidUntil);
flow.set("refreshToken", msg.payload.refreshToken);
flow.set("refreshTokenValidUntil", msg.payload.refreshTokenValidUntil);

node.status({
    fill: "green",
    shape: "dot",
    text: "Token ważny do: " + new Date(msg.payload.accessTokenValidUntil).toLocaleTimeString()
});

return msg;

// invoices-metadata-hwm-sync-node oczekuje:
// msg.topic = "authToken"
// msg.payload.accessToken.token = string
return {
    topic: "authToken",
    payload: {
        accessToken: {
            token: msg.payload.accessToken
        }
    }
};

const accessToken = flow.get("accessToken");
const validUntil = flow.get("accessTokenValidUntil");
const refreshToken = flow.get("refreshToken");

if (!accessToken || !validUntil || !refreshToken) {
    node.warn("Brak tokenów – uruchom najpierw autentykację");
    return null;
}

const expiresAt = new Date(validUntil).getTime();
const now = Date.now();
const bufferMs = 5 * 60 * 1000; // 5-minutowy zapas

if (expiresAt - now > bufferMs) {
    const minutesLeft = Math.round((expiresAt - now) / 60000);
    node.status({ fill: "green", shape: "dot", text: "OK – ważny jeszcze " + minutesLeft + " min" });
    return null; // token wciąż ważny
}

// Token wkrótce wygaśnie – odświeżamy
node.status({ fill: "yellow", shape: "ring", text: "Odświeżanie..." });
// refresh-token-node oczekuje: msg.accessToken = wartość REFRESH tokenu
return { accessToken: refreshToken };

// refresh-token-node zwraca:
// msg.payload = { newTokenValue, newTokenValidUntil }
flow.set("accessToken", msg.payload.newTokenValue);
flow.set("accessTokenValidUntil", msg.payload.newTokenValidUntil);

node.status({
    fill: "green",
    shape: "dot",
    text: "Odświeżono, ważny do: " + new Date(msg.payload.newTokenValidUntil).toLocaleTimeString()
});

// Poinformuj węzeł synchronizacji o nowym tokenie
return {
    topic: "authToken",
    payload: {
        accessToken: {
            token: msg.payload.newTokenValue
        }
    }
};

const accessToken = flow.get("accessToken");
if (!accessToken) {
    node.error("Brak tokenu – uruchom najpierw autentykację");
    return null;
}
// ksef-init-session oczekuje: msg.accessToken = string
return { accessToken };

// ksef-send-invoice zwraca:
// msg.payload.sendInvoiceResult = { ksefNumber, ... }
// msg.originalMsg = oryginalna wiadomość (zawiera referenceNumber sesji)
const sendResult = msg.payload.sendInvoiceResult;
node.log("Faktura wysłana, numer KSeF: " + sendResult.ksefNumber);

// ksef-close-session oczekuje: { accessToken, referenceNumber }
return {
    accessToken: flow.get("accessToken"),
    referenceNumber: msg.originalMsg.referenceNumber
};

// Synchronizuj faktury z ostatnich 7 dni (dostosuj wg potrzeb)
msg.topic = "from";
msg.payload = {
    dateFrom: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString()
};
return msg;

// invoices-metadata-hwm-sync-node zwraca:
// msg.payload = InvoiceMetadata { ksefNumber, invoiceNumber, issueDate, ... }
const invoice = msg.payload;
const accessToken = flow.get("accessToken");

if (!accessToken) {
    node.warn("Brak tokenu – sprawdź autentykację");
    return null;
}

if (!invoice.ksefNumber) {
    node.warn("Faktura bez numeru KSeF – pomijam");
    return null;
}

// download-invoice-node oczekuje: { ksefNumber, authToken, payload: InvoiceMetadata }
return {
    ksefNumber: invoice.ksefNumber,
    authToken: accessToken,
    payload: invoice
};

const meta = msg.payload.decodedMsg;

// Formatujemy datę wystawienia na DD-MM-RRRR
const issueDateObj = new Date(meta.issueDate);
const day = String(issueDateObj.getDate()).padStart(2, '0');
const month = String(issueDateObj.getMonth() + 1).padStart(2, '0');
const year = issueDateObj.getFullYear();
const issueDate = `${day}-${month}-${year}`;

// Generujemy URL QR
const qrCodeURL = `https://qr-demo.ksef.mf.gov.pl/invoice/${meta.seller.nip}/${issueDate}/${meta.invoiceHash}`;

// Zwracamy gotowy obiekt
return {
    xml: msg.payload.invoiceTxt,
    ksefNumber: meta.ksefNumber,
    qrCodeURL: qrCodeURL,
    isMobile: "false"
};

const base64pdf = msg.payload;
msg.headers = { "Content-Type": "text/html" };
msg.payload = `<!DOCTYPE html>
<html lang="pl">
<head><meta charset="UTF-8"><title>Faktura KSeF</title></head>
<body style="margin:0">
  <embed src="data:application/pdf;base64,${base64pdf}" type="application/pdf" width="100%" height="100%" style="position:absolute;top:0;left:0;width:100%;height:100%">
</body>
</html>`;
return msg;
